   366→// In-memory rate limiter: 20 requests per hour per auth token
   367→const RATE_LIMIT_MAX = 20;
   368→const RATE_LIMIT_WINDOW_MS = 60 * 60 * 1000; // 1 hour
   369→
   370→interface RateLimitEntry {
   371→  count: number;
   372→  windowStart: number;
   373→}
   374→
   375→const rateLimitMap = new Map<string, RateLimitEntry>();
   376→
   377→function checkRateLimit(token: string): { allowed: boolean; retryAfterSec?: number } {
   378→  const now = Date.now();
   379→  const entry = rateLimitMap.get(token);
   380→
   381→  if (!entry || now - entry.windowStart > RATE_LIMIT_WINDOW_MS) {
   382→    rateLimitMap.set(token, { count: 1, windowStart: now });
   383→    return { allowed: true };
   384→  }
   385→
   386→  if (entry.count >= RATE_LIMIT_MAX) {
   387→    const retryAfterSec = Math.ceil((entry.windowStart + RATE_LIMIT_WINDOW_MS - now) / 1000);
   388→    return { allowed: false, retryAfterSec };
   389→  }
   390→
   391→  entry.count++;
   392→  return { allowed: true };
   393→}
